parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "status": {
      "type": "string",
      "description": "Either 'PROFILE_DATA_FOUND' or 'NO_PROFILE_DATA_FOUND'"
    },
    "evidence": {
      "type": "object",
      "properties": {
        "skills": { "type": "string", "description": "Evidence for PHP, Magento, Linux" },
        "role": { "type": "string", "description": "Evidence for ERP/Dynamics 365" },
        "seniority": { "type": "string", "description": "Evidence for 20+ years experience" },
        "tooling": { "type": "string", "description": "Evidence for C#, Azure, Windows Server" }
      }
    }
  },
  "required": ["status", "evidence"]
}

{
  "type": "object",
  "properties": {
    "calculation_steps": {
      "type": "array",
      "items": { "type": "string" },
      "description": "Step-by-step breakdown of the 45/25/20/10 math"
    },
    "final_score": {
      "type": "integer",
      "minimum": 1,
      "maximum": 100,
      "description": "The final weighted match score"
    }
  },
  "required": ["calculation_steps", "final_score"]
}

{
  "type": "object",
  "properties": {
    "id": {
      "type": "string",
      "description": "The unique identifier or URL of the job advertisement."
    },
    "title": {
      "type": "string",
      "description": "The official job title from the advertisement."
    },
    "match_score_percentage": {
      "type": "integer",
      "minimum": 1,
      "maximum": 100,
      "description": "The final calculated weighted score from the Analyst."
    }
  },
  "required": ["id", "title", "match_score_percentage"],
  "additionalProperties": false
}
